using Ledgerly.Application.Invoices; using Microsoft.AspNetCore.Mvc; namespace Ledgerly.Api.Controllers; [ApiController][Route("api/organizations/{organizationId:guid}/invoices")] public sealed class InvoicesController:ControllerBase{ private readonly InvoiceService _s; public InvoicesController(InvoiceService s)=>_s=s; [HttpGet("{invoiceId:guid}")] public async Task<IActionResult> Get(Guid organizationId,Guid invoiceId,CancellationToken ct=default){var r=await _s.GetByIdAsync(organizationId,invoiceId,ct);return r.IsFailure?NotFound(new{error=r.Error}):Ok(r.Value);} [HttpPost] public async Task<IActionResult> Create(Guid organizationId,[FromBody]CreateInvoiceRequest req,CancellationToken ct=default){var r=await _s.CreateAsync(req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{invoiceId:guid}/lines")] public async Task<IActionResult> AddLine(Guid organizationId,Guid invoiceId,[FromBody]AddInvoiceLineRequest req,CancellationToken ct=default){var r=await _s.AddLineAsync(organizationId,invoiceId,req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{invoiceId:guid}/send")] public async Task<IActionResult> Send(Guid organizationId,Guid invoiceId,CancellationToken ct=default){var r=await _s.SendAsync(organizationId,invoiceId,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{invoiceId:guid}/payments")] public async Task<IActionResult> Pay(Guid organizationId,Guid invoiceId,[FromBody]RecordPaymentRequest req,CancellationToken ct=default){var r=await _s.RecordPaymentAsync(organizationId,invoiceId,req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{invoiceId:guid}/void")] public async Task<IActionResult> Void(Guid organizationId,Guid invoiceId,CancellationToken ct=default){var r=await _s.VoidAsync(organizationId,invoiceId,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} }
